package main

import (
	"errors"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns the average latency in milliseconds.
// It uses the os/exec package to execute the ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	// Build the ping command arguments
	// -c for count on Unix-like systems, -n for Windows
	// We'll try to detect the OS, but for simplicity, we'll assume Unix-like
	// In a real-world scenario, you might want to handle Windows differently
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, errors.New("failed to execute ping command: " + string(output))
	}

	// Parse the output to find the average latency
	// Look for a line like: rtt min/avg/max/mdev = 10.234/20.456/30.789/5.123 ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches := re.FindStringSubmatch(string(output))
	if len(matches) < 2 {
		// Try alternative pattern for different ping outputs
		// Some systems might have different formats
		re2 := regexp.MustCompile(`Average = ([\d.]+)ms`)
		matches = re2.FindStringSubmatch(string(output))
		if len(matches) < 2 {
			return 0, errors.New("could not parse ping output to extract average latency")
		}
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, errors.New("failed to parse average latency value: " + err.Error())
	}

	return avg, nil
}

