)

// MeasureLatency pings a specified host a user-defined number of times and returns the average latency in milliseconds.
// It uses the os/exec package to execute the ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	// Build the ping command arguments
	// The -c flag is used on Unix-like systems to specify the count
	// Note: This implementation assumes a Unix-like system with ping command
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, errors.New("failed to execute ping command: " + string(output))
	}

	// Parse the output to find the average latency
	// Look for a line containing "avg" or similar that has the statistics
	// Typical output format: rtt min/avg/max/mdev = 10.234/20.456/30.789/5.123 ms
	lines := strings.Split(string(output), "\n")
	var avgLine string
	for _, line := range lines {
		if strings.Contains(line, "avg") || strings.Contains(line, "min/avg/max") {
			avgLine = line
			break
		}
	}

	if avgLine == "" {
		return 0, errors.New("could not find average latency in ping output")
	}

	// Extract the average value using regex
	// Match pattern like "10.234/20.456/30.789" where the second number is avg
	re := regexp.MustCompile(`(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)`)
	matches := re.FindStringSubmatch(avgLine)
	if len(matches) < 3 {
		return 0, errors.New("could not parse average latency from ping output")
	}

	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, errors.New("failed to parse average latency: " + err.Error())
	}

	return avg, nil
}

