// parsePingOutput extracts the average latency from ping command output
func parsePingOutput(output string) (float64, error) {
	scanner := bufio.NewScanner(strings.NewReader(output))

	// Look for lines containing "avg" or "average"
	for scanner.Scan() {
		line := scanner.Text()

		// Common pattern in Unix ping output: rtt min/avg/max/mdev = 10.234/20.456/30.789/5.123 ms
		if strings.Contains(line, "avg") || strings.Contains(line, "Average") {
			// Extract numbers from the line
			re := regexp.MustCompile(`[0-9]*\.?[0-9]+`)
			numbers := re.FindAllString(line, -1)

			// In the standard Unix output format, the second number is the average
			if len(numbers) >= 2 {
