			if strings.Contains(line, "Average") && strings.Contains(line, "=") {
				parts := strings.Split(line, "=")
				if len(parts) == 2 {
					avgStr := strings.TrimSpace(parts[1])
					avgStr = strings.TrimSuffix(avgStr, "ms")
					avgStr = strings.TrimSpace(avgStr)
					if avg, err := strconv.ParseFloat(avgStr, 64); err == nil {
						return avg, nil
					}
				}
			}
