package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build ping command - note that on Windows, the flag is different
	// For cross-platform compatibility, we need to handle both cases
	var cmd *exec.Cmd
	switch {
	case isWindows():
		// On Windows, ping uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// On Unix-like systems, ping uses -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string

	// Different patterns for different OS
	if isWindows() {
		// Windows ping output format example:
		// Approximate round trip times in milli-seconds:
		//     Minimum = 10ms, Maximum = 20ms, Average = 15ms
		for i, line := range lines {
			if strings.Contains(line, "Approximate round trip times") && i+1 < len(lines) {
				// The next line should contain the stats
				statsLine = lines[i+1]
				break
			}
		}
	} else {
		// Unix-like systems
		for _, line := range lines {
			if strings.Contains(line, "rtt min/avg/max") {
				statsLine = line
				break
			}
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	var avg float64
	var parseErr error

	if isWindows() {
		// Parse Windows format: "    Minimum = 10ms, Maximum = 20ms, Average = 15ms"
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from Windows ping output")
		}
		avgInt, err := strconv.Atoi(matches[1])
		if err != nil {
			return 0, fmt.Errorf("failed to convert average latency to integer: %w", err)
		}
		avg = float64(avgInt)
	} else {
		// Parse Unix format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
		re := regexp.MustCompile(`rtt min/avg/max/mdev = \d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+ ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			// Some systems might have slightly different formats, try a more flexible regex
			re2 := regexp.MustCompile(`= [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
			matches = re2.FindStringSubmatch(statsLine)
			if len(matches) < 2 {
				return 0, errors.New("failed to parse average latency from ping output")
			}
		}
		avgStr := matches[1]
		avg, parseErr = strconv.ParseFloat(avgStr, 64)
		if parseErr != nil {
			return 0, fmt.Errorf("failed to convert average latency to float: %w", parseErr)
		}
	}

	return avg, nil
}

