		}
	}

	// Parse the output to find average latency
	avgLatency, err := parsePingOutput(string(output))
	if err != nil {
		return 0, err
	}

	return avgLatency, nil
}

// parsePingOutput extracts the average latency from ping command output
func parsePingOutput(output string) (float64, error) {
	scanner := bufio.NewScanner(strings.NewReader(output))

	// Look for lines containing "avg" or "Average" which typically contain the statistics
	for scanner.Scan() {
		line := scanner.Text()

		// Handle Unix-like ping output (e.g., "rtt min/avg/max/mdev = 10.5/20.3/30.1/5.2 ms")
		if strings.Contains(line, "avg") && strings.Contains(line, "=") {
			// Extract the part after "="
			parts := strings.Split(line, "=")
			if len(parts) > 1 {
				// Split by "/" to get individual values
				values := strings.Split(parts[1], "/")
				if len(values) >= 2 {
					// The second value is typically the average
					avgStr := strings.TrimSpace(values[1])
					// Remove "ms" if present
					avgStr = strings.TrimSuffix(avgStr, " ms")
					avgStr = strings.TrimSuffix(avgStr, "ms")
					return strconv.ParseFloat(avgStr, 64)
				}
			}
		}

		// Handle Windows ping output (e.g., "Average = 20ms")
		if strings.Contains(line, "Average") && strings.Contains(line, "=") {
			// Use regex to extract the number before "ms"
			re := regexp.MustCompile(`Average\s*=\s*(\d+\.?\d*)`)
			matches := re.FindStringSubmatch(line)
			if len(matches) > 1 {
				return strconv.ParseFloat(matches[1], 64)
			}
		}
	}

	return 0, errors.New("could not parse average latency from ping output")
