import (
	"bufio"
	"errors"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	// Build the ping command
	// Note: Different operating systems have different ping command syntax
	// For Unix-like systems (Linux, macOS), we use -c for count
	// For Windows, it would be -n, but this implementation assumes Unix-like
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, errors.New("failed to execute ping command: " + string(output))
	}

	// Parse the output to find average latency
	// Look for line containing "avg" or similar statistics
	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	var avgLine string
	for scanner.Scan() {
		line := scanner.Text()
		if strings.Contains(line, "avg") || strings.Contains(line, "Average") {
			avgLine = line
			break
		}
	}

	if avgLine == "" {
		return 0, errors.New("could not find average latency in ping output")
	}

	// Extract the average value using regex
	// Common format: rtt min/avg/max/mdev = 10.234/20.456/30.789/5.123 ms
	re := regexp.MustCompile(`.*?([\d.]+)/[\d.]+/[\d.]+.*?ms`)
	matches := re.FindStringSubmatch(avgLine)
	if len(matches) < 2 {
		// Try alternative pattern for different ping output formats
		re2 := regexp.MustCompile(`Average = ([\d.]+)ms`)
		matches = re2.FindStringSubmatch(avgLine)
		if len(matches) < 2 {
			return 0, errors.New("could not parse average latency from ping output")
		}
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, errors.New("failed to parse average latency value: " + err.Error())
	}

	return avg, nil
}

