func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	// Build the ping command
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS, etc.)
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, errors.New("failed to execute ping command: " + string(output))
	}

	// Parse the output to extract average latency
	avgLatency, parseErr := parsePingOutput(string(output))
	if parseErr != nil {
		return 0, parseErr
	}

	return avgLatency, nil
}

// parsePingOutput parses the output from the ping command and returns the average latency in milliseconds.
func parsePingOutput(output string) (float64, error) {
	// Handle Unix/Linux/macOS ping output
	// Example: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	unixRegex := regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	unixMatches := unixRegex.FindStringSubmatch(output)
	if len(unixMatches) > 1 {
		avg, err := strconv.ParseFloat(unixMatches[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Handle Windows ping output
	// Example: Average = 23ms
	windowsRegex := regexp.MustCompile(`Average = (\d+)ms`)
	windowsMatches := windowsRegex.FindStringSubmatch(output)
	if len(windowsMatches) > 1 {
		avg, err := strconv.Atoi(windowsMatches[1])
		if err == nil {
			return float64(avg), nil
		}
	}

	// Alternative Windows format (with decimal)
	windowsRegex2 := regexp.MustCompile(`Average = ([\d.]+)ms`)
	windowsMatches2 := windowsRegex2.FindStringSubmatch(output)
	if len(windowsMatches2) > 1 {
		avg, err := strconv.ParseFloat(windowsMatches2[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Try to find any line containing "avg" or "average" case-insensitively
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		lowerLine := strings.ToLower(line)
		if strings.Contains(lowerLine, "avg") || strings.Contains(lowerLine, "average") {
			// Extract numbers from the line
			numRegex := regexp.MustCompile(`[\d.]+`)
			numbers := numRegex.FindAllString(line, -1)
			if len(numbers) > 0 {
				// Usually the average is one of the numbers, often the second or third
				// Try the last number first as it might be the average in some formats
				for i := len(numbers) - 1; i >= 0; i-- {
					if avg, err := strconv.ParseFloat(numbers[i], 64); err == nil {
						return avg, nil
					}
				}
			}
		}
	}

	return 0, errors.New("could not parse ping output to extract average latency")
}

