package main

import (
	"bufio"
	"errors"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a user-defined number of times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	// Build the ping command
	// Note: On Windows, the flag for count is -n, but on Unix-like systems it's -c
	// For simplicity and since the problem doesn't specify OS, we'll assume Unix-like
	// In a production environment, you might want to detect the OS and adjust accordingly
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, errors.New("failed to execute ping command: " + string(output))
	}

	// Parse the output to find the average latency
	// The ping output typically ends with a line like:
	// rtt min/avg/max/mdev = 10.123/20.456/30.789/5.123 ms
	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	var avgLine string
	for scanner.Scan() {
		line := scanner.Text()
		if strings.Contains(line, "avg") && strings.Contains(line, "=") {
			avgLine = line
			break
		}
	}

	if avgLine == "" {
		return 0, errors.New("could not find average latency in ping output")
	}

	// Extract the average value using regex
	// Looking for pattern like "min/avg/max/mdev = X.XXX/Y.YYY/Z.ZZZ/W.WWW ms"
	re := regexp.MustCompile(`=.*?/([0-9]*\.?[0-9]+)`)
	matches := re.FindStringSubmatch(avgLine)
	if len(matches) < 2 {
		return 0, errors.New("could not parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, errors.New("failed to parse average latency: " + err.Error())
	}

	return avg, nil
}

