package main

import (
	"bufio"
	"errors"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	// Build the ping command
	// Note: On Windows, the flag for count is -n, while on Unix-like systems it's -c
	// For simplicity and portability, we'll assume a Unix-like system here
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, errors.New("failed to execute ping command: " + string(output))
	}

	// Parse the output to find average latency
	// Typical output line: rtt min/avg/max/mdev = 10.123/20.456/30.789/5.123 ms
	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	avgLatency := 0.0
	found := false

	for scanner.Scan() {
		line := scanner.Text()
		if strings.Contains(line, "avg") && strings.Contains(line, "min/avg/max") {
			// Extract the average value using regex
			re := regexp.MustCompile(`.*?(\d+\.\d+)/\d+\.\d+/\d+\.\d+.*`)
			matches := re.FindStringSubmatch(line)
			if len(matches) > 1 {
				avgStr := matches[1]
				avgLatency, err = strconv.ParseFloat(avgStr, 64)
				if err != nil {
					return 0, errors.New("failed to parse average latency from ping output")
				}
				found = true
				break
			}
		}
	}

	if !found {
		// Try alternative parsing for different ping output formats
		// Some systems might have different output format
		scanner = bufio.NewScanner(strings.NewReader(string(output)))
		sum := 0.0
		parsedCount := 0
		timeRegex := regexp.MustCompile(`time=(\d+(?:\.\d+)?)\s*ms`)

		for scanner.Scan() {
			line := scanner.Text()
			matches := timeRegex.FindStringSubmatch(line)
			if len(matches) > 1 {
				timeVal, err := strconv.ParseFloat(matches[1], 64)
				if err == nil {
					sum += timeVal
					parsedCount++
				}
			}
		}

		if parsedCount > 0 {
			avgLatency = sum / float64(parsedCount)
			found = true
		}
	}

	if !found {
		return 0, errors.New("could not parse latency information from ping output")
	}

	return avgLatency, nil
}

